@RestController
@RequestMapping("/api/webhook")
class WebhookController {

    private final RestTemplate restTemplate;
    private final UrlValidator urlValidator;

    public WebhookController(RestTemplate restTemplate, UrlValidator urlValidator) {
        this.restTemplate = restTemplate;
        this.urlValidator = urlValidator;
    }

    @PostMapping("/fetch")
    public ResponseEntity<?> handleWebhook(@RequestBody WebhookRequest request) {
        if (request == null || request.getUrl() == null || request.getUrl().isBlank()) {
            return ResponseEntity.badRequest().body(Map.of("error", "URL is required"));
        }

        String targetUrl = request.getUrl().trim();

        try {
            urlValidator.validate(targetUrl);
        } catch (SsrfException e) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN)
                    .body(Map.of("error", "URL not allowed: " + e.getMessage()));
        }

        try {
            String response = restTemplate.getForObject(targetUrl, String.class);
            return ResponseEntity.ok(Map.of(
                    "status", "success",
                    "content", response != null ? response : ""
            ));
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.BAD_GATEWAY)
                    .body(Map.of("error", "Failed to fetch content: " + e.getMessage()));
        }
    }
}

