@org.springframework.stereotype.Component
class UrlValidator {

    private static final Set<String> ALLOWED_SCHEMES = Set.of("http", "https");

    private static final Set<String> ALLOWED_DOMAINS = Set.of(
            "api.partner1.com",
            "api.partner2.com",
            "hooks.partner3.com"
    );

    private static final List<String> BLOCKED_IP_PREFIXES = List.of(
            "10.",
            "172.16.", "172.17.", "172.18.", "172.19.",
            "172.20.", "172.21.", "172.22.", "172.23.",
            "172.24.", "172.25.", "172.26.", "172.27.",
            "172.28.", "172.29.", "172.30.", "172.31.",
            "192.168.",
            "127.",
            "0.",
            "169.254.",
            "fc00:", "fd00:",
            "fe80:",
            "::1",
            "0:0:0:0:0:0:0:1"
    );

    public void validate(String urlString) throws SsrfException {
        URL url;
        try {
            url = new URL(urlString);
        } catch (MalformedURLException e) {
            throw new SsrfException("Malformed URL");
        }

        String scheme = url.getProtocol().toLowerCase();
        if (!ALLOWED_SCHEMES.contains(scheme)) {
            throw new SsrfException("Scheme not allowed: " + scheme);
        }

        String host = url.getHost();
        if (host == null || host.isBlank()) {
            throw new SsrfException("Host is empty");
        }

        host = host.toLowerCase();

        // Reject URLs with userinfo (e.g., http://user@evil.com)
        if (url.getUserInfo() != null) {
            throw new SsrfException("URLs with user info are not allowed");
        }

        // Allowlist check on the hostname
        if (!ALLOWED_DOMAINS.contains(host)) {
            throw new SsrfException("Domain not in allowlist: " + host);
        }

        // Resolve DNS and check that the resolved IP is not internal/private
        InetAddress[] addresses;
        try {
            addresses = InetAddress.getAllByName(host);
        } catch (UnknownHostException e) {
            throw new SsrfException("Cannot resolve host: " + host);
        }

        for (InetAddress address : addresses) {
            if (address.isLoopbackAddress()
                    || address.isLinkLocalAddress()
                    || address.isSiteLocalAddress()
                    || address.isAnyLocalAddress()
                    || address.isMulticastAddress()) {
                throw new SsrfException("Resolved IP address is not allowed (private/internal): " + address.getHostAddress());
            }

            String ipString = address.getHostAddress();
            for (String prefix : BLOCKED_IP_PREFIXES) {
                if (ipString.startsWith(prefix)) {
                    throw new SsrfException("Resolved IP address is blocked: " + ipString);
                }
            }
        }

        // Block non-standard ports (only allow 80 and 443)
        int port = url.getPort();
        if (port != -1 && port != 80 && port != 443) {
            throw new SsrfException("Port not allowed: " + port);
        }
    }
}